        if pred == "activeYearsStartYear":
            return f"started activity in {o}"
        if pred == "activeYearsEndYear":
            return f"ended activity in {o}"
        if pred == "language" or pred == "officialLanguage":
            return f"has official language {o}"
        if pred == "capital":
            return f"has capital {o}"
        if pred == "currency":
            return f"uses the currency {o}"
        if pred == "anthem":
